package org.example.project.util

import kotlinx.browser.localStorage
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json
import org.example.project.model.MeasurementHistory

actual class StorageService {
    private val json = Json {
        ignoreUnknownKeys = true
        prettyPrint = false
    }

    actual fun saveHistory(history: MeasurementHistory) {
        try {
            val jsonString = json.encodeToString(history)
            localStorage.setItem(HISTORY_KEY, jsonString)
        } catch (e: Exception) {
            console.error("Failed to save history:", e.message)
        }
    }

    actual fun loadHistory(): MeasurementHistory {
        return try {
            val jsonString = localStorage.getItem(HISTORY_KEY)
            if (jsonString != null) {
                json.decodeFromString<MeasurementHistory>(jsonString)
            } else {
                MeasurementHistory()
            }
        } catch (e: Exception) {
            console.error("Failed to load history:", e.message)
            MeasurementHistory()
        }
    }

    actual fun saveLanguage(languageCode: String) {
        try {
            localStorage.setItem(LANGUAGE_KEY, languageCode)
        } catch (e: Exception) {
            console.error("Failed to save language:", e.message)
        }
    }

    actual fun loadLanguage(): String? {
        return try {
            localStorage.getItem(LANGUAGE_KEY)
        } catch (e: Exception) {
            console.error("Failed to load language:", e.message)
            null
        }
    }

    actual fun saveCookieConsent(consent: org.example.project.model.CookieConsent) {
        try {
            val jsonString = json.encodeToString(consent)
            localStorage.setItem(COOKIE_CONSENT_KEY, jsonString)
        } catch (e: Exception) {
            console.error("Failed to save cookie consent:", e.message)
        }
    }

    actual fun loadCookieConsent(): org.example.project.model.CookieConsent? {
        return try {
            val jsonString = localStorage.getItem(COOKIE_CONSENT_KEY)
            if (jsonString != null) {
                json.decodeFromString<org.example.project.model.CookieConsent>(jsonString)
            } else {
                null
            }
        } catch (e: Exception) {
            console.error("Failed to load cookie consent:", e.message)
            null
        }
    }

    companion object {
        private const val HISTORY_KEY = "snake_measurer_history"
        private const val LANGUAGE_KEY = "snake_measurer_language"
        private const val COOKIE_CONSENT_KEY = "snake_measurer_cookie_consent"
    }
}
