package org.example.project.model

import kotlinx.serialization.Serializable
import org.example.project.util.PlatformInfo

/**
 * Represents user's cookie consent preferences
 */
@Serializable
data class CookieConsent(
    val essential: Boolean = true, // Always true, cannot be disabled
    val analytics: Boolean = false, // Google Analytics
    val marketing: Boolean = false, // Marketing/advertising cookies (future use)
    val timestamp: Long = PlatformInfo.currentTimeMillis(),
    val hasResponded: Boolean = false // Has the user responded to the banner
)
