package org.example.project.model

import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.graphics.ImageBitmap

/**
 * Represents the current state of measurement
 */
data class MeasurementState(
    val imageBitmap: ImageBitmap? = null,
    val imageUri: String? = null,
    val referencePoints: List<MeasurementPoint> = emptyList(),
    val snakePoints: List<MeasurementPoint> = emptyList(),
    val referenceLengthCm: Float = 10f, // Default reference length in cm
    val calculatedSnakeLengthCm: Float = 0f,
    val imageScale: Float = 1f,
    val selectedPointId: String? = null,
    val mode: MeasurementMode = MeasurementMode.REFERENCE,
    val selectedUnit: MeasurementUnit = MeasurementUnit.CENTIMETERS,
    val zoomLevel: Float = 1f, // 1.0 = 100% zoom
    val panOffset: Offset = Offset.Zero, // Pan offset in screen coordinates
    val minZoom: Float = 0.5f,
    val maxZoom: Float = 5.0f,
    val measurementHistory: MeasurementHistory = MeasurementHistory(),
    val cookieConsent: CookieConsent? = null,
    val showCookieBanner: Boolean = false,
    val currentLanguage: Language = Language.ENGLISH
)

enum class MeasurementMode {
    REFERENCE,  // Placing reference object points
    SNAKE,      // Placing snake measurement points
    EDIT        // Editing/moving existing points
}
