package org.example.project.ui.screens

import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.verticalScroll
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import org.example.project.model.CookieConsent
import org.example.project.ui.components.CookieConsentBanner
import org.example.project.ui.components.CookiePreferencesDialog
import org.example.project.ui.components.MeasurementCanvas
import org.example.project.ui.components.MeasurementToolbar
import org.example.project.ui.theme.AppColors
import org.example.project.viewmodel.MeasurementViewModel

@Composable
fun MeasurementScreen(
    onLoadImage: () -> Unit,
    modifier: Modifier = Modifier,
    viewModel: MeasurementViewModel = viewModel { MeasurementViewModel() }
) {
    val state = viewModel.state
    var showPreferencesDialog by remember { mutableStateOf(false) }

    // Determine layout based on available width
    Box(
        modifier = modifier
            .fillMaxSize()
            .background(AppColors.Background)
    ) {
        BoxWithConstraints(
            modifier = Modifier.fillMaxSize()
        ) {
            val isWideScreen = maxWidth > 800.dp

            if (isWideScreen) {
                // Tablet/Desktop layout - Side by side
                Row(modifier = Modifier.fillMaxSize()) {
                    // Toolbar on the left
                    Box(
                        modifier = Modifier
                            .width(360.dp)
                            .fillMaxHeight()
                            .verticalScroll(rememberScrollState())
                    ) {
                        MeasurementToolbar(
                            viewModel = viewModel,
                            onLoadImage = onLoadImage
                        )
                    }

                    // Canvas on the right
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .fillMaxHeight()
                            .background(AppColors.SurfaceDark)
                            .padding(16.dp)
                    ) {
                        MeasurementCanvas(viewModel = viewModel)
                    }
                }
            } else {
                // Phone layout - Vertical stack
                Column(modifier = Modifier.fillMaxSize()) {

//                val d = maxHeight.value;
                    // Toolbar at top (scrollable, takes needed space with max limit)
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .heightIn(max = (this@BoxWithConstraints.maxHeight.value * 0.5f).dp) // Max 50% of screen height
                            .verticalScroll(rememberScrollState())
                            .padding(bottom = 8.dp)
                    ) {
                        MeasurementToolbar(
                            viewModel = viewModel,
                            onLoadImage = onLoadImage
                        )
                    }

                    // Canvas at bottom (takes remaining space)
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(1f) // Takes all remaining space
                            .background(AppColors.SurfaceDark)
                            .padding(8.dp)
                    ) {
                        MeasurementCanvas(viewModel = viewModel)
                    }
                }
            }

            // Cookie consent banner (overlay at bottom)
            if (state.showCookieBanner) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .align(Alignment.BottomCenter)
                        .padding(16.dp)
                ) {
                    CookieConsentBanner(
                        onAcceptAll = { viewModel.acceptAllCookies() },
                        onRejectNonEssential = { viewModel.rejectNonEssentialCookies() },
                        onManagePreferences = { showPreferencesDialog = true }
                    )
                }
            }

            // Cookie preferences dialog
            if (showPreferencesDialog) {
                CookiePreferencesDialog(
                    currentConsent = state.cookieConsent ?: CookieConsent(),
                    onSave = { consent ->
                        viewModel.setCustomCookieConsent(consent)
                        showPreferencesDialog = false
                    },
                    onDismiss = { showPreferencesDialog = false }
                )
            }
        }
    }
}
