package org.example.project.model

import net.sergeych.sprintf.format
import net.sergeych.sprintf.sprintf

/**
 * Represents different measurement units supported by the application
 */
enum class MeasurementUnit(
    val abbreviation: String,
    val displayName: String,
    val cmMultiplier: Float // How many cm in one unit
) {
    CENTIMETERS("cm", "Centimeters", 1f),
    MILLIMETERS("mm", "Millimeters", 0.1f),
    METERS("m", "Meters", 100f),
    INCHES("in", "Inches", 2.54f),
    FEET("ft", "Feet", 30.48f);

    /**
     * Convert from this unit to centimeters
     */
    fun toCentimeters(value: Float): Float {
        return value * cmMultiplier
    }

    /**
     * Convert from centimeters to this unit
     */
    fun fromCentimeters(valueCm: Float): Float {
        return valueCm / cmMultiplier
    }

    /**
     * Format a value in this unit for display
     */
    fun format(value: Float, decimals: Int = 2): String {
        return "%.${decimals}f".format(value)
    }

    /**
     * Format a value with unit abbreviation
     */
    fun formatWithUnit(value: Float, decimals: Int = 2): String {
        return "${format(value, decimals)} $abbreviation"
    }
}
