package org.example.project.ui

import androidx.compose.runtime.Composable
import androidx.compose.runtime.CompositionLocalProvider
import androidx.compose.runtime.compositionLocalOf
import org.example.project.model.Language
import org.example.project.resources.StringsRepository

/**
 * Composition local for accessing the current language
 */
val LocalLanguage = compositionLocalOf { Language.ENGLISH }

/**
 * Provider for language context
 */
@Composable
fun ProvideLanguage(
    language: Language,
    content: @Composable () -> Unit
) {
    CompositionLocalProvider(LocalLanguage provides language) {
        content()
    }
}

/**
 * Composable function to get a localized string
 * Usage: val text = stringResource("app_title")
 */
@Composable
fun stringResource(key: String, vararg args: Any): String {
    val language = LocalLanguage.current
    return if (args.isEmpty()) {
        StringsRepository.getString(key, language)
    } else {
        StringsRepository.getString(key, language, *args)
    }
}
