package org.example.project.ui.components

import androidx.compose.foundation.Canvas
import androidx.compose.foundation.gestures.awaitEachGesture
import androidx.compose.foundation.gestures.awaitFirstDown
import androidx.compose.foundation.gestures.detectTransformGestures
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clipToBounds
import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.geometry.Size
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.Paint
import androidx.compose.ui.graphics.PaintingStyle
import androidx.compose.ui.graphics.drawscope.drawIntoCanvas
import androidx.compose.ui.input.pointer.PointerEventType
import androidx.compose.ui.input.pointer.pointerInput
import androidx.compose.ui.input.pointer.positionChange
import androidx.compose.ui.unit.IntOffset
import org.example.project.model.MeasurementMode
import org.example.project.model.MeasurementPoint
import org.example.project.util.CoordinateTransform
import org.example.project.viewmodel.MeasurementViewModel
import kotlin.math.sqrt

@Composable
fun MeasurementCanvas(
    viewModel: MeasurementViewModel,
    modifier: Modifier = Modifier
) {
    val state = viewModel.state
    val tapThreshold = 15f // Max movement to still be considered a tap
    val dragThreshold = 10f // Min movement to start drag/pan

    Canvas(
        modifier = modifier
            .fillMaxSize()
            .clipToBounds()
            // Mouse wheel zoom support for web/desktop
            .pointerInput(Unit) {
                awaitEachGesture {
                    val event = awaitPointerEvent()
                    if (event.type == PointerEventType.Scroll) {
                        val scrollDelta = event.changes.firstOrNull()?.scrollDelta ?: Offset.Zero
                        if (scrollDelta.y != 0f) {
                            state.imageBitmap?.let { bitmap ->
                                val imageSize = Size(bitmap.width.toFloat(), bitmap.height.toFloat())
                                val canvasSize = Size(size.width.toFloat(), size.height.toFloat())
                                val position = event.changes.firstOrNull()?.position ?: Offset.Zero

                                // Zoom in/out based on scroll direction
                                val zoomDelta = -scrollDelta.y * 0.1f * state.zoomLevel
                                viewModel.adjustZoom(
                                    delta = zoomDelta,
                                    focalPoint = position,
                                    imageSize = imageSize,
                                    canvasSize = canvasSize
                                )
                            }
                            event.changes.forEach { it.consume() }
                        }
                    }
                }
            }
            // Transform gestures for pinch zoom
            .pointerInput(Unit) {
                detectTransformGestures { centroid, pan, zoom, _ ->
                    state.imageBitmap?.let { bitmap ->
                        val imageSize = Size(bitmap.width.toFloat(), bitmap.height.toFloat())
                        val canvasSize = Size(size.width.toFloat(), size.height.toFloat())

                        // Handle pinch zoom
                        if (zoom != 1f) {
                            val zoomDelta = (zoom - 1f) * state.zoomLevel
                            viewModel.adjustZoom(
                                delta = zoomDelta,
                                focalPoint = centroid,
                                imageSize = imageSize,
                                canvasSize = canvasSize
                            )
                        }

                        // Handle pan during pinch
                        if (pan != Offset.Zero && state.zoomLevel > 1f) {
                            val newPan = state.panOffset + pan
                            viewModel.setPan(newPan, imageSize, canvasSize)
                        }
                    }
                }
            }
            // Combined tap and drag handling
            .pointerInput(state.mode, state.selectedPointId, state.zoomLevel) {
                awaitEachGesture {
                    val down = awaitFirstDown(requireUnconsumed = false)
                    val downPosition = down.position
                    var totalDrag = Offset.Zero
                    var isDraggingPoint = false
                    var isPanning = false
                    var dragStarted = false

                    state.imageBitmap?.let { bitmap ->
                        val imageSize = Size(bitmap.width.toFloat(), bitmap.height.toFloat())
                        val canvasSize = Size(size.width.toFloat(), size.height.toFloat())

                        // Check if we're near a point for dragging in edit mode
                        if (state.mode == MeasurementMode.EDIT) {
                            val nearestPoint = findNearestPointInScreenSpace(
                                downPosition, state, imageSize, canvasSize
                            )
                            if (nearestPoint != null) {
                                viewModel.selectPoint(nearestPoint.id)
                                isDraggingPoint = true
                            }
                        }

                        // Process pointer movements
                        do {
                            val event = awaitPointerEvent()
                            val change = event.changes.firstOrNull() ?: break

                            if (event.type == PointerEventType.Move) {
                                val dragAmount = change.positionChange()
                                totalDrag += dragAmount

                                val totalMovement = sqrt(totalDrag.x * totalDrag.x + totalDrag.y * totalDrag.y)

                                // Start drag/pan after threshold
                                if (totalMovement > dragThreshold && !dragStarted) {
                                    dragStarted = true
                                    if (!isDraggingPoint && state.zoomLevel > 1f) {
                                        isPanning = true
                                    }
                                }

                                if (dragStarted) {
                                    if (isDraggingPoint && state.selectedPointId != null) {
                                        // Move selected point
                                        val normalizedPos = CoordinateTransform.screenToNormalized(
                                            screenOffset = change.position,
                                            imageSize = imageSize,
                                            canvasSize = canvasSize,
                                            zoom = state.zoomLevel,
                                            pan = state.panOffset
                                        )
                                        viewModel.moveSelectedPoint(normalizedPos)
                                    } else if (isPanning) {
                                        // Pan the canvas
                                        val newPan = state.panOffset + dragAmount
                                        viewModel.setPan(newPan, imageSize, canvasSize)
                                    }
                                }
                            }

                            if (event.type == PointerEventType.Release) {
                                val totalMovement = sqrt(totalDrag.x * totalDrag.x + totalDrag.y * totalDrag.y)

                                // If minimal movement, treat as tap
                                if (totalMovement < tapThreshold) {
                                    when (state.mode) {
                                        MeasurementMode.REFERENCE, MeasurementMode.SNAKE -> {
                                            val normalizedPos = CoordinateTransform.screenToNormalized(
                                                screenOffset = downPosition,
                                                imageSize = imageSize,
                                                canvasSize = canvasSize,
                                                zoom = state.zoomLevel,
                                                pan = state.panOffset
                                            )
                                            viewModel.addPoint(normalizedPos)
                                        }
                                        MeasurementMode.EDIT -> {
                                            val nearestPoint = findNearestPointInScreenSpace(
                                                downPosition, state, imageSize, canvasSize
                                            )
                                            if (nearestPoint != null) {
                                                viewModel.selectPoint(nearestPoint.id)
                                            } else {
                                                viewModel.unselectPoint()
                                            }
                                        }
                                    }
                                }
                                break
                            }
                        } while (event.changes.any { it.pressed })
                    }
                }
            }
    ) {
        // Draw image if available with zoom and pan
        state.imageBitmap?.let { bitmap ->
            val imageSize = Size(bitmap.width.toFloat(), bitmap.height.toFloat())
            val canvasSize = size
            val imageBounds = CoordinateTransform.getImageBounds(
                imageSize, canvasSize, state.zoomLevel, state.panOffset
            )

            drawImage(
                image = bitmap,
                dstOffset = IntOffset(imageBounds.left.toInt(), imageBounds.top.toInt()),
                dstSize = androidx.compose.ui.unit.IntSize(
                    imageBounds.width.toInt(),
                    imageBounds.height.toInt()
                )
            )

            // Draw reference lines (convert from normalized to screen coords)
            if (state.referencePoints.size >= 2) {
                val start = CoordinateTransform.normalizedToScreen(
                    state.referencePoints[0].position,
                    imageSize, canvasSize, state.zoomLevel, state.panOffset
                )
                val end = CoordinateTransform.normalizedToScreen(
                    state.referencePoints[1].position,
                    imageSize, canvasSize, state.zoomLevel, state.panOffset
                )
                drawLine(
                    color = Color(0xFF4CAF50),
                    start = start,
                    end = end,
                    strokeWidth = 4f * state.zoomLevel
                )
            }

            // Draw snake path (convert from normalized to screen coords)
            if (state.snakePoints.size >= 2) {
                for (i in 0 until state.snakePoints.size - 1) {
                    val start = CoordinateTransform.normalizedToScreen(
                        state.snakePoints[i].position,
                        imageSize, canvasSize, state.zoomLevel, state.panOffset
                    )
                    val end = CoordinateTransform.normalizedToScreen(
                        state.snakePoints[i + 1].position,
                        imageSize, canvasSize, state.zoomLevel, state.panOffset
                    )
                    drawLine(
                        color = Color(0xFF2196F3),
                        start = start,
                        end = end,
                        strokeWidth = 3f * state.zoomLevel
                    )
                }
            }

            // Draw reference points (convert from normalized to screen coords)
            state.referencePoints.forEach { point ->
                val screenPos = CoordinateTransform.normalizedToScreen(
                    point.position,
                    imageSize, canvasSize, state.zoomLevel, state.panOffset
                )
                drawPoint(
                    position = screenPos,
                    color = Color(0xFF4CAF50),
                    isSelected = point.id == state.selectedPointId,
                    zoom = state.zoomLevel
                )
            }

            // Draw snake points (convert from normalized to screen coords)
            state.snakePoints.forEach { point ->
                val screenPos = CoordinateTransform.normalizedToScreen(
                    point.position,
                    imageSize, canvasSize, state.zoomLevel, state.panOffset
                )
                drawPoint(
                    position = screenPos,
                    color = Color(0xFF2196F3),
                    isSelected = point.id == state.selectedPointId,
                    zoom = state.zoomLevel
                )
            }
        }
    }
}

/**
 * Find the nearest point to a screen position, accounting for zoom/pan transformations
 */
private fun findNearestPointInScreenSpace(
    screenOffset: Offset,
    state: org.example.project.model.MeasurementState,
    imageSize: Size,
    canvasSize: Size,
    maxDistance: Float = 50f
): MeasurementPoint? {
    val allPoints = state.referencePoints + state.snakePoints
    var nearestPoint: MeasurementPoint? = null
    var minDistance = maxDistance

    allPoints.forEach { point ->
        val screenPos = CoordinateTransform.normalizedToScreen(
            point.position, imageSize, canvasSize, state.zoomLevel, state.panOffset
        )
        val distance = sqrt(
            (screenPos.x - screenOffset.x) * (screenPos.x - screenOffset.x) +
            (screenPos.y - screenOffset.y) * (screenPos.y - screenOffset.y)
        )
        if (distance < minDistance) {
            minDistance = distance
            nearestPoint = point
        }
    }

    return nearestPoint
}

private fun androidx.compose.ui.graphics.drawscope.DrawScope.drawPoint(
    position: Offset,
    color: Color,
    isSelected: Boolean,
    zoom: Float = 1f
) {
    // Scale point sizes based on zoom for better visibility
    val baseRadius = 12f
    val selectionRadius = 24f

    // Draw outer circle (selection indicator)
    if (isSelected) {
        drawCircle(
            color = color.copy(alpha = 0.3f),
            radius = selectionRadius,
            center = position
        )
    }

    // Draw main point circle
    drawCircle(
        color = color,
        radius = baseRadius,
        center = position
    )

    // Draw inner white circle
    drawCircle(
        color = Color.White,
        radius = baseRadius / 2f,
        center = position
    )

    // Draw border
    drawIntoCanvas { canvas ->
        val paint = Paint().apply {
            this.color = Color.White
            this.strokeWidth = 2f
            this.style = PaintingStyle.Stroke
        }
        canvas.drawCircle(position, baseRadius, paint)
    }
}
