package org.example.project.util

import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.geometry.Rect
import androidx.compose.ui.geometry.Size
import kotlin.math.max
import kotlin.math.min

/**
 * Utility object for transforming coordinates between screen space and normalized image space
 * with zoom and pan transformations
 */
object CoordinateTransform {

    /**
     * Convert screen coordinates to normalized image coordinates (0.0-1.0)
     * @param screenOffset The position in screen/canvas coordinates
     * @param imageSize The size of the actual image
     * @param canvasSize The size of the canvas displaying the image
     * @param zoom The current zoom level (1.0 = 100%)
     * @param pan The current pan offset in screen coordinates
     * @return Offset in normalized image coordinates (0.0-1.0)
     */
    fun screenToNormalized(
        screenOffset: Offset,
        imageSize: Size,
        canvasSize: Size,
        zoom: Float,
        pan: Offset
    ): Offset {
        // Calculate the base scale to fit image in canvas
        val baseScale = calculateFitScale(imageSize, canvasSize)

        // Calculate actual image dimensions on screen
        val displayedImageWidth = imageSize.width * baseScale * zoom
        val displayedImageHeight = imageSize.height * baseScale * zoom

        // Calculate image position on canvas (centered + pan)
        val imageLeft = (canvasSize.width - displayedImageWidth) / 2f + pan.x
        val imageTop = (canvasSize.height - displayedImageHeight) / 2f + pan.y

        // Convert screen position to position relative to image
        val relativeX = screenOffset.x - imageLeft
        val relativeY = screenOffset.y - imageTop

        // Normalize to 0.0-1.0 range
        val normalizedX = relativeX / displayedImageWidth
        val normalizedY = relativeY / displayedImageHeight

        return Offset(normalizedX, normalizedY)
    }

    /**
     * Convert normalized image coordinates (0.0-1.0) to screen coordinates
     * @param normalizedOffset The position in normalized image coordinates
     * @param imageSize The size of the actual image
     * @param canvasSize The size of the canvas displaying the image
     * @param zoom The current zoom level (1.0 = 100%)
     * @param pan The current pan offset in screen coordinates
     * @return Offset in screen/canvas coordinates
     */
    fun normalizedToScreen(
        normalizedOffset: Offset,
        imageSize: Size,
        canvasSize: Size,
        zoom: Float,
        pan: Offset
    ): Offset {
        // Calculate the base scale to fit image in canvas
        val baseScale = calculateFitScale(imageSize, canvasSize)

        // Calculate actual image dimensions on screen
        val displayedImageWidth = imageSize.width * baseScale * zoom
        val displayedImageHeight = imageSize.height * baseScale * zoom

        // Calculate image position on canvas (centered + pan)
        val imageLeft = (canvasSize.width - displayedImageWidth) / 2f + pan.x
        val imageTop = (canvasSize.height - displayedImageHeight) / 2f + pan.y

        // Convert normalized to relative position on displayed image
        val relativeX = normalizedOffset.x * displayedImageWidth
        val relativeY = normalizedOffset.y * displayedImageHeight

        // Convert to screen coordinates
        return Offset(
            x = imageLeft + relativeX,
            y = imageTop + relativeY
        )
    }

    /**
     * Get the bounds of the displayed image in screen coordinates
     * @param imageSize The size of the actual image
     * @param canvasSize The size of the canvas displaying the image
     * @param zoom The current zoom level (1.0 = 100%)
     * @param pan The current pan offset in screen coordinates
     * @return Rect representing the image bounds in screen space
     */
    fun getImageBounds(
        imageSize: Size,
        canvasSize: Size,
        zoom: Float,
        pan: Offset
    ): Rect {
        val baseScale = calculateFitScale(imageSize, canvasSize)

        val displayedImageWidth = imageSize.width * baseScale * zoom
        val displayedImageHeight = imageSize.height * baseScale * zoom

        val imageLeft = (canvasSize.width - displayedImageWidth) / 2f + pan.x
        val imageTop = (canvasSize.height - displayedImageHeight) / 2f + pan.y

        return Rect(
            left = imageLeft,
            top = imageTop,
            right = imageLeft + displayedImageWidth,
            bottom = imageTop + displayedImageHeight
        )
    }

    /**
     * Calculate the scale needed to fit the image within the canvas while maintaining aspect ratio
     */
    private fun calculateFitScale(imageSize: Size, canvasSize: Size): Float {
        val scaleX = canvasSize.width / imageSize.width
        val scaleY = canvasSize.height / imageSize.height
        return min(scaleX, scaleY)
    }

    /**
     * Constrain pan offset to prevent image from being panned too far
     * @param pan The desired pan offset
     * @param imageSize The size of the actual image
     * @param canvasSize The size of the canvas displaying the image
     * @param zoom The current zoom level
     * @return Constrained pan offset
     */
    fun constrainPan(
        pan: Offset,
        imageSize: Size,
        canvasSize: Size,
        zoom: Float
    ): Offset {
        if (zoom <= 1f) {
            // At or below 100% zoom, don't allow panning
            return Offset.Zero
        }

        val baseScale = calculateFitScale(imageSize, canvasSize)
        val displayedImageWidth = imageSize.width * baseScale * zoom
        val displayedImageHeight = imageSize.height * baseScale * zoom

        // Calculate the maximum allowed pan in each direction
        // This ensures at least part of the image is always visible
        val maxPanX = (displayedImageWidth - canvasSize.width) / 2f
        val maxPanY = (displayedImageHeight - canvasSize.height) / 2f

        return Offset(
            x = pan.x.coerceIn(-maxPanX, maxPanX),
            y = pan.y.coerceIn(-maxPanY, maxPanY)
        )
    }

    /**
     * Adjust zoom level focused on a specific point
     * @param currentZoom Current zoom level
     * @param zoomDelta Change in zoom (positive = zoom in)
     * @param focalPoint Point to zoom towards in screen coordinates
     * @param currentPan Current pan offset
     * @param imageSize Size of the image
     * @param canvasSize Size of the canvas
     * @return Pair of new zoom and new pan offset
     */
    fun adjustZoomAtPoint(
        currentZoom: Float,
        zoomDelta: Float,
        focalPoint: Offset,
        currentPan: Offset,
        imageSize: Size,
        canvasSize: Size,
        minZoom: Float = 0.5f,
        maxZoom: Float = 5.0f
    ): Pair<Float, Offset> {
        val newZoom = (currentZoom + zoomDelta).coerceIn(minZoom, maxZoom)

        if (newZoom == currentZoom) {
            // Zoom didn't change (hit limits)
            return Pair(currentZoom, currentPan)
        }

        // Calculate the point in normalized coordinates
        val normalizedPoint = screenToNormalized(
            focalPoint, imageSize, canvasSize, currentZoom, currentPan
        )

        // Calculate where that point should be after zoom
        val newScreenPoint = normalizedToScreen(
            normalizedPoint, imageSize, canvasSize, newZoom, Offset.Zero
        )

        // Adjust pan to keep the focal point in the same screen position
        val panAdjustment = focalPoint - newScreenPoint
        val newPan = constrainPan(
            currentPan + panAdjustment,
            imageSize, canvasSize, newZoom
        )

        return Pair(newZoom, newPan)
    }
}
