package org.example.project.ui.components

import androidx.compose.foundation.background
import androidx.compose.foundation.border
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.compose.ui.window.Dialog
import org.example.project.model.CookieConsent
import org.example.project.ui.theme.AppColors
import org.example.project.util.PlatformInfo

@Composable
fun CookieConsentBanner(
    onAcceptAll: () -> Unit,
    onRejectNonEssential: () -> Unit,
    onManagePreferences: () -> Unit,
    modifier: Modifier = Modifier
) {
    Box(
        modifier = modifier
            .fillMaxWidth()
            .background(Color.White)
            .border(2.dp, AppColors.GrayLight)
            .padding(16.dp)
    ) {
        Column(
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            // Title
            CustomText(
                text = "🍪 Cookie Preferences",
                fontSize = 18.sp,
                color = AppColors.TextPrimary,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
            )

            // Description
            CustomText(
                text = "We use cookies to enhance your experience. Essential cookies are required for the app to function. Analytics cookies help us improve the app.",
                fontSize = 12.sp,
                color = AppColors.TextSecondary
            )

            // Buttons
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                CustomButton(
                    text = "Reject",
                    onClick = onRejectNonEssential,
                    backgroundColor = AppColors.GrayLight,
                    modifier = Modifier.weight(1f)
                )
                CustomButton(
                    text = "Manage",
                    onClick = onManagePreferences,
                    backgroundColor = AppColors.Accent.copy(alpha = 0.3f),
                    modifier = Modifier.weight(1f)
                )
                CustomButton(
                    text = "Accept All",
                    onClick = onAcceptAll,
                    backgroundColor = AppColors.Accent,
                    modifier = Modifier.weight(1f)
                )
            }
        }
    }
}

@Composable
fun CookiePreferencesDialog(
    currentConsent: CookieConsent,
    onSave: (CookieConsent) -> Unit,
    onDismiss: () -> Unit
) {
    var analytics by remember { mutableStateOf(currentConsent.analytics) }
    var marketing by remember { mutableStateOf(currentConsent.marketing) }

    Dialog(onDismissRequest = onDismiss) {
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color.White, RoundedCornerShape(12.dp))
                .border(2.dp, AppColors.GrayLight, RoundedCornerShape(12.dp))
                .padding(24.dp)
        ) {
            Column(
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                // Title
                CustomText(
                    text = "Cookie Preferences",
                    fontSize = 20.sp,
                    color = AppColors.Primary,
                    fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
                )

                // Essential cookies (always enabled)
                CookieOption(
                    title = "Essential Cookies",
                    description = "Required for the app to function properly. Cannot be disabled.",
                    enabled = true,
                    isEnabled = true,
                    onToggle = {}
                )

                // Analytics cookies
                CookieOption(
                    title = "Analytics Cookies",
                    description = "Help us understand how you use the app to improve your experience.",
                    enabled = true,
                    isEnabled = analytics,
                    onToggle = { analytics = !analytics }
                )

                // Marketing cookies (for future use)
                CookieOption(
                    title = "Marketing Cookies",
                    description = "Used to show you relevant content and advertisements.",
                    enabled = true,
                    isEnabled = marketing,
                    onToggle = { marketing = !marketing }
                )

                // Buttons
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    CustomButton(
                        text = "Cancel",
                        onClick = onDismiss,
                        backgroundColor = AppColors.GrayLight,
                        modifier = Modifier.weight(1f)
                    )
                    CustomButton(
                        text = "Save Preferences",
                        onClick = {
                            val newConsent = CookieConsent(
                                essential = true,
                                analytics = analytics,
                                marketing = marketing,
                                timestamp = PlatformInfo.currentTimeMillis(),
                                hasResponded = true
                            )
                            onSave(newConsent)
                        },
                        backgroundColor = AppColors.Accent,
                        modifier = Modifier.weight(1f)
                    )
                }
            }
        }
    }
}

@Composable
private fun CookieOption(
    title: String,
    description: String,
    enabled: Boolean,
    isEnabled: Boolean,
    onToggle: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .background(AppColors.GrayLight.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
            .padding(12.dp),
        verticalArrangement = Arrangement.spacedBy(4.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            CustomText(
                text = title,
                fontSize = 14.sp,
                color = AppColors.TextPrimary,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold,
                modifier = Modifier.weight(1f)
            )

            // Toggle switch (simplified as a button for now)
            CustomButton(
                text = if (isEnabled) "ON" else "OFF",
                onClick = if (enabled) onToggle else {{}},
                backgroundColor = if (isEnabled) AppColors.Accent else AppColors.GrayLight,
                enabled = enabled,
                modifier = Modifier.width(60.dp)
            )
        }

        CustomText(
            text = description,
            fontSize = 11.sp,
            color = AppColors.TextSecondary
        )
    }
}
