package org.example.project.model

import kotlinx.serialization.Serializable

/**
 * Represents a single saved measurement record
 */
@Serializable
data class MeasurementRecord(
    val id: String,
    val timestamp: Long, // Unix timestamp in milliseconds
    val snakeLengthCm: Float, // Always stored in cm for consistency
    val unit: MeasurementUnit, // Unit that was selected when measurement was taken
    val referenceLengthCm: Float, // Reference length in cm
    val snakePointCount: Int // Number of points used for the measurement
)

/**
 * Container for measurement history
 * Maintains only the last 5 measurements
 */
@Serializable
data class MeasurementHistory(
    val records: List<MeasurementRecord> = emptyList()
) {
    /**
     * Add a new record, keeping only the last 5 measurements
     */
    fun addRecord(record: MeasurementRecord): MeasurementHistory {
        val updatedRecords = (records + record)
            .sortedByDescending { it.timestamp }
            .take(5)
        return copy(records = updatedRecords)
    }

    /**
     * Remove a record by ID
     */
    fun removeRecord(id: String): MeasurementHistory {
        return copy(records = records.filter { it.id != id })
    }

    /**
     * Get records sorted by timestamp (newest first)
     */
    fun getSortedRecords(): List<MeasurementRecord> {
        return records.sortedByDescending { it.timestamp }
    }
}
