package org.example.project.viewmodel

import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.geometry.Size
import androidx.compose.ui.graphics.ImageBitmap
import androidx.lifecycle.ViewModel
import org.example.project.model.CookieConsent
import org.example.project.model.Language
import org.example.project.model.MeasurementHistory
import org.example.project.model.MeasurementMode
import org.example.project.model.MeasurementPoint
import org.example.project.model.MeasurementRecord
import org.example.project.model.MeasurementState
import org.example.project.model.MeasurementUnit
import org.example.project.model.PointType
import org.example.project.util.Analytics
import org.example.project.util.CoordinateTransform
import org.example.project.util.MeasurementCalculator
import org.example.project.util.PlatformInfo
import org.example.project.util.StorageService
import org.example.project.util.UuidGenerator

class MeasurementViewModel(
    private val storageService: StorageService = StorageService()
) : ViewModel() {

    var state by mutableStateOf(MeasurementState())
        private set

    init {
        // Load saved history on initialization
        loadHistory()

        // Load saved language
        loadLanguage()

        // Load cookie consent and show banner if needed (web only)
        if (PlatformInfo.isWeb) {
            loadCookieConsent()
        }
    }

    fun setImage(imageBitmap: ImageBitmap, imageUri: String) {
        state = state.copy(
            imageBitmap = imageBitmap,
            imageUri = imageUri,
            referencePoints = emptyList(),
            snakePoints = emptyList(),
            calculatedSnakeLengthCm = 0f,
            mode = MeasurementMode.REFERENCE
        )
    }

    fun setMode(mode: MeasurementMode) {
        state = state.copy(mode = mode, selectedPointId = null)
    }

    fun addPoint(position: Offset) {
        when (state.mode) {
            MeasurementMode.REFERENCE -> {
                if (state.referencePoints.size < 2) {
                    val newPoint = MeasurementPoint(
                        id = UuidGenerator.randomUUID(),
                        position = position,
                        type = PointType.REFERENCE
                    )
                    state = state.copy(
                        referencePoints = state.referencePoints + newPoint
                    )
                }
            }
            MeasurementMode.SNAKE -> {
                val newPoint = MeasurementPoint(
                    id = UuidGenerator.randomUUID(),
                    position = position,
                    type = PointType.SNAKE
                )
                state = state.copy(
                    snakePoints = state.snakePoints + newPoint
                )
                updateSnakeLength()
            }
            MeasurementMode.EDIT -> {
                // In edit mode, clicking without selecting moves to add mode
                // This is handled by the UI
            }
        }
    }

    fun selectPoint(pointId: String) {
        state = state.copy(selectedPointId = pointId, mode = MeasurementMode.EDIT)
    }

    fun moveSelectedPoint(newPosition: Offset) {
        val selectedId = state.selectedPointId ?: return

        // Check if it's a reference point
        val referenceIndex = state.referencePoints.indexOfFirst { it.id == selectedId }
        if (referenceIndex != -1) {
            val updatedPoints = state.referencePoints.toMutableList()
            updatedPoints[referenceIndex] = updatedPoints[referenceIndex].copy(position = newPosition)
            state = state.copy(referencePoints = updatedPoints)
            updateSnakeLength()
            return
        }

        // Check if it's a snake point
        val snakeIndex = state.snakePoints.indexOfFirst { it.id == selectedId }
        if (snakeIndex != -1) {
            val updatedPoints = state.snakePoints.toMutableList()
            updatedPoints[snakeIndex] = updatedPoints[snakeIndex].copy(position = newPosition)
            state = state.copy(snakePoints = updatedPoints)
            updateSnakeLength()
        }
    }

    fun deletePoint(pointId: String) {
        // Try to remove from reference points
        val updatedReferencePoints = state.referencePoints.filter { it.id != pointId }
        val updatedSnakePoints = state.snakePoints.filter { it.id != pointId }

        state = state.copy(
            referencePoints = updatedReferencePoints,
            snakePoints = updatedSnakePoints,
            selectedPointId = null
        )
        updateSnakeLength()
    }

    fun setReferenceLength(length: Float) {
        // Convert from selected unit to cm for internal storage
        val lengthCm = state.selectedUnit.toCentimeters(length)
        state = state.copy(referenceLengthCm = lengthCm)
        updateSnakeLength()
    }

    fun setUnit(unit: MeasurementUnit) {
        state = state.copy(selectedUnit = unit)
    }

    fun clearAllPoints() {
        state = state.copy(
            referencePoints = emptyList(),
            snakePoints = emptyList(),
            calculatedSnakeLengthCm = 0f,
            selectedPointId = null,
            mode = MeasurementMode.REFERENCE
        )
    }

    fun clearSnakePoints() {
        state = state.copy(
            snakePoints = emptyList(),
            calculatedSnakeLengthCm = 0f,
            selectedPointId = null
        )
    }

    fun deleteLastSnakePoint() {
        if (state.snakePoints.isNotEmpty()) {
            state = state.copy(
                snakePoints = state.snakePoints.dropLast(1),
                selectedPointId = null
            )
            updateSnakeLength()
        }
    }

    fun findNearestPoint(position: Offset, maxDistance: Float = 50f): MeasurementPoint? {
        val allPoints = state.referencePoints + state.snakePoints
        return MeasurementCalculator.findNearestPoint(position, allPoints, maxDistance)
    }

    private fun updateSnakeLength() {
        if (state.snakePoints.size >= 2 && state.referencePoints.size == 2) {
            val snakeLength = MeasurementCalculator.calculateSnakeLengthInCm(
                snakePoints = state.snakePoints,
                referencePoints = state.referencePoints,
                referenceLengthCm = state.referenceLengthCm
            )
            state = state.copy(calculatedSnakeLengthCm = snakeLength)

            // Auto-save measurement when completed
            if (snakeLength > 0) {
                saveMeasurement(snakeLength)
            }
        } else {
            state = state.copy(calculatedSnakeLengthCm = 0f)
        }
    }

    fun unselectPoint() {
        state = state.copy(selectedPointId = null)
    }

    // Zoom and pan functions
    fun setZoom(zoom: Float) {
        val constrainedZoom = zoom.coerceIn(state.minZoom, state.maxZoom)
        state = state.copy(zoomLevel = constrainedZoom)
    }

    fun setPan(offset: Offset, imageSize: Size, canvasSize: Size) {
        val constrainedPan = CoordinateTransform.constrainPan(
            offset, imageSize, canvasSize, state.zoomLevel
        )
        state = state.copy(panOffset = constrainedPan)
    }

    fun adjustZoom(delta: Float, focalPoint: Offset, imageSize: Size, canvasSize: Size) {
        val (newZoom, newPan) = CoordinateTransform.adjustZoomAtPoint(
            currentZoom = state.zoomLevel,
            zoomDelta = delta,
            focalPoint = focalPoint,
            currentPan = state.panOffset,
            imageSize = imageSize,
            canvasSize = canvasSize,
            minZoom = state.minZoom,
            maxZoom = state.maxZoom
        )
        state = state.copy(
            zoomLevel = newZoom,
            panOffset = newPan
        )
    }

    fun resetZoom() {
        state = state.copy(
            zoomLevel = 1f,
            panOffset = Offset.Zero
        )
    }

    // History management functions
    private fun loadHistory() {
        val history = storageService.loadHistory()
        state = state.copy(measurementHistory = history)
    }

    private fun saveMeasurement(snakeLengthCm: Float) {
        val record = MeasurementRecord(
            id = UuidGenerator.randomUUID(),
            timestamp = PlatformInfo.currentTimeMillis(),
            snakeLengthCm = snakeLengthCm,
            unit = state.selectedUnit,
            referenceLengthCm = state.referenceLengthCm,
            snakePointCount = state.snakePoints.size
        )

        val updatedHistory = state.measurementHistory.addRecord(record)
        state = state.copy(measurementHistory = updatedHistory)
        storageService.saveHistory(updatedHistory)
    }

    fun deleteHistoryRecord(recordId: String) {
        val updatedHistory = state.measurementHistory.removeRecord(recordId)
        state = state.copy(measurementHistory = updatedHistory)
        storageService.saveHistory(updatedHistory)
    }

    // Cookie consent functions
    private fun loadCookieConsent() {
        val consent = storageService.loadCookieConsent()
        if (consent == null) {
            // No consent saved, show banner
            state = state.copy(
                cookieConsent = null,
                showCookieBanner = true
            )
        } else {
            // Consent already saved
            state = state.copy(
                cookieConsent = consent,
                showCookieBanner = false
            )
            // Initialize analytics if consent given
            if (consent.analytics) {
                Analytics.initialize(true)
            }
        }
    }

    fun acceptAllCookies() {
        val consent = CookieConsent(
            essential = true,
            analytics = true,
            marketing = true,
            timestamp = PlatformInfo.currentTimeMillis(),
            hasResponded = true
        )
        saveCookieConsent(consent)
        Analytics.initialize(true)
        Analytics.trackEvent("Cookie Consent", "Accept All", null)
    }

    fun rejectNonEssentialCookies() {
        val consent = CookieConsent(
            essential = true,
            analytics = false,
            marketing = false,
            timestamp = PlatformInfo.currentTimeMillis(),
            hasResponded = true
        )
        saveCookieConsent(consent)
        Analytics.initialize(false)
    }

    fun setCustomCookieConsent(consent: CookieConsent) {
        saveCookieConsent(consent)
        Analytics.initialize(consent.analytics)
        if (consent.analytics) {
            Analytics.trackEvent("Cookie Consent", "Custom", "Analytics: ${consent.analytics}, Marketing: ${consent.marketing}")
        }
    }

    private fun saveCookieConsent(consent: CookieConsent) {
        state = state.copy(
            cookieConsent = consent,
            showCookieBanner = false
        )
        storageService.saveCookieConsent(consent)
    }

    fun showCookiePreferences() {
        state = state.copy(showCookieBanner = true)
    }

    // Language management functions
    private fun loadLanguage() {
        val languageCode = storageService.loadLanguage()
        if (languageCode != null) {
            val language = Language.fromCode(languageCode)
            state = state.copy(currentLanguage = language)
        }
    }

    fun setLanguage(language: Language) {
        state = state.copy(currentLanguage = language)
        storageService.saveLanguage(language.code)

        // Track language change if analytics enabled
        if (state.cookieConsent?.analytics == true) {
            Analytics.trackEvent("Language", "Change", language.code)
        }
    }
}
