package org.example.project

import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.lifecycle.viewmodel.compose.viewModel
import org.example.project.ui.ProvideLanguage
import org.example.project.ui.screens.MeasurementScreen
import org.example.project.util.rememberImagePicker
import org.example.project.viewmodel.MeasurementViewModel
import org.jetbrains.compose.ui.tooling.preview.Preview

@Composable
@Preview
fun App() {
    val viewModel: MeasurementViewModel = viewModel { MeasurementViewModel() }

    val imagePicker = rememberImagePicker { imageBitmap, uri ->
        viewModel.setImage(imageBitmap, uri)
    }

    // Wrap app with language provider
    ProvideLanguage(language = viewModel.state.currentLanguage) {
        MeasurementScreen(
            onLoadImage = imagePicker,
            viewModel = viewModel,
            modifier = Modifier.fillMaxSize()
        )
    }
}
