package org.example.project.util

import androidx.compose.runtime.Composable
import androidx.compose.runtime.remember
import androidx.compose.ui.graphics.ImageBitmap
import androidx.compose.ui.graphics.toComposeImageBitmap
import kotlinx.browser.document
import kotlinx.browser.window
import org.jetbrains.skia.Image
import org.khronos.webgl.ArrayBuffer
import org.khronos.webgl.Int8Array
import org.khronos.webgl.get
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.url.URL
import org.w3c.files.File
import org.w3c.files.FileReader
import org.w3c.files.get

@Composable
actual fun rememberImagePicker(
    onImageSelected: (ImageBitmap, String) -> Unit
): () -> Unit {
    return remember {
        {
            // Create a hidden file input element
            val input = document.createElement("input") as HTMLInputElement
            input.type = "file"
            input.accept = "image/*"

            input.onchange = { event ->
                val file = input.files?.get(0)
                if (file != null) {
                    val reader = FileReader()
                    reader.onload = {
                        try {
                            val arrayBuffer = reader.result as ArrayBuffer
                            val byteArray = Int8Array(arrayBuffer)
                            val bytes = ByteArray(byteArray.length) { byteArray[it] }

                            val image = Image.makeFromEncoded(bytes)
                            val imageBitmap = image.toComposeImageBitmap()

                            // Create object URL for the file
                            val objectUrl = URL.createObjectURL(file)
                            onImageSelected(imageBitmap, objectUrl)
                        } catch (e: Exception) {
                            console.log("Error loading image: ${e.message}")
                        }
                        null
                    }
                    reader.readAsArrayBuffer(file)
                }
                null
            }

            // Trigger the file picker
            input.click()
        }
    }
}