package org.example.project.ui.components

import androidx.compose.foundation.background
import androidx.compose.foundation.border
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import org.example.project.model.MeasurementHistory
import org.example.project.model.MeasurementRecord
import org.example.project.model.MeasurementUnit
import org.example.project.ui.stringResource
import org.example.project.ui.theme.AppColors
import org.example.project.util.PlatformInfo

@Composable
fun HistoryDisplay(
    history: MeasurementHistory,
    currentUnit: MeasurementUnit,
    onDeleteRecord: (String) -> Unit,
    modifier: Modifier = Modifier
) {
    var isExpanded by remember { mutableStateOf(false) }
    val sortedRecords = history.getSortedRecords()

    Column(
        modifier = modifier.fillMaxWidth(),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        // Header with toggle
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            CustomText(
                text = stringResource("history", sortedRecords.size),
                fontSize = 14.sp,
                color = AppColors.TextSecondary,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
            )
            if (sortedRecords.isNotEmpty()) {
                CustomButton(
                    text = if (isExpanded) stringResource("hide") else stringResource("show"),
                    onClick = { isExpanded = !isExpanded },
                    backgroundColor = AppColors.GrayLight,
                    modifier = Modifier.width(80.dp)
                )
            }
        }

        // Expandable history list
        if (isExpanded && sortedRecords.isNotEmpty()) {
            LazyColumn(
                modifier = Modifier
                    .fillMaxWidth()
                    .heightIn(max = 300.dp)
                    .background(Color.White, RoundedCornerShape(8.dp))
                    .border(1.dp, AppColors.GrayLight, RoundedCornerShape(8.dp))
                    .padding(4.dp),
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                items(sortedRecords, key = { it.id }) { record ->
                    HistoryRecordItem(
                        record = record,
                        currentUnit = currentUnit,
                        onDelete = { onDeleteRecord(record.id) }
                    )
                }
            }
        } else if (isExpanded && sortedRecords.isEmpty()) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(AppColors.GrayLight.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
                    .padding(16.dp),
                contentAlignment = Alignment.Center
            ) {
                CustomText(
                    text = stringResource("no_measurements"),
                    fontSize = 12.sp,
                    color = AppColors.TextSecondary
                )
            }
        }
    }
}

@Composable
private fun HistoryRecordItem(
    record: MeasurementRecord,
    currentUnit: MeasurementUnit,
    onDelete: () -> Unit
) {
    // Convert length to current unit for display
    val lengthInCurrentUnit = currentUnit.fromCentimeters(record.snakeLengthCm)
    val formattedLength = currentUnit.formatWithUnit(lengthInCurrentUnit)

    // Format timestamp
    val timestamp = formatTimestamp(record.timestamp)

    Row(
        modifier = Modifier
            .fillMaxWidth()
            .background(Color.White, RoundedCornerShape(6.dp))
            .border(1.dp, AppColors.GrayLight, RoundedCornerShape(6.dp))
            .padding(8.dp),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Column(
            modifier = Modifier.weight(1f),
            verticalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            // Length and timestamp
            CustomText(
                text = formattedLength,
                fontSize = 16.sp,
                color = AppColors.Accent,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
            )
            CustomText(
                text = timestamp,
                fontSize = 11.sp,
                color = AppColors.TextSecondary
            )
            // Additional info
            CustomText(
                text = "${record.snakePointCount} ${stringResource("points")} • ${stringResource("ref")} ${record.unit.formatWithUnit(record.unit.fromCentimeters(record.referenceLengthCm))}",
                fontSize = 10.sp,
                color = AppColors.TextSecondary
            )
        }

        // Delete button
        CustomButton(
            text = "🗑️",
            onClick = onDelete,
            backgroundColor = AppColors.Error.copy(alpha = 0.1f),
            modifier = Modifier.size(36.dp)
        )
    }
}

/**
 * Format Unix timestamp to readable string
 */
@Composable
private fun formatTimestamp(timestamp: Long): String {
    val now = PlatformInfo.currentTimeMillis()
    val diff = now - timestamp

    return when {
        diff < 60_000L -> stringResource("just_now")
        diff < 3_600_000L -> stringResource("minutes_ago", diff / 60_000L)
        diff < 86_400_000L -> stringResource("hours_ago", diff / 3_600_000L)
        else -> stringResource("days_ago", diff / 86_400_000L)
    }
}
