@Composable
fun MeasurementToolbar(
    viewModel: MeasurementViewModel,
    onLoadImage: () -> Unit,
    modifier: Modifier = Modifier
) {
    val state = viewModel.state

    Column(
        modifier = modifier
            .fillMaxWidth()
            .background(AppColors.Surface)
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        // Language selector
        LanguageSelector(
            currentLanguage = state.currentLanguage,
            onLanguageSelected = { viewModel.setLanguage(it) }
        )

        Spacer(modifier = Modifier.height(8.dp))

        // Title
        CustomText(
            text = stringResource("app_title"),
            fontSize = 24.sp,
            color = AppColors.Primary,
            fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
        )

        // Load image button
        if (state.imageBitmap == null) {
            CustomButton(
                text = stringResource("load_image"),
                onClick = onLoadImage,
                backgroundColor = AppColors.Accent,
                modifier = Modifier.fillMaxWidth()
            )
        } else {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                CustomButton(
                    text = stringResource("change_image"),
                    onClick = onLoadImage,
                    backgroundColor = AppColors.GrayLight,
                    modifier = Modifier.weight(1f)
                )
                CustomButton(
                    text = stringResource("clear_all"),
                    onClick = { viewModel.clearAllPoints() },
                    backgroundColor = AppColors.Error,
                    modifier = Modifier.weight(1f)
                )
            }
        }

        if (state.imageBitmap != null) {
            Spacer(modifier = Modifier.height(8.dp))

            // Reference section
            CustomText(
                text = stringResource("reference_object"),
                fontSize = 16.sp,
                color = AppColors.Reference,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
            )

            ReferenceSection(
                viewModel = viewModel,
                pointCount = state.referencePoints.size
            )

            Spacer(modifier = Modifier.height(8.dp))

            // Zoom controls
            ZoomControlsSection(viewModel = viewModel)

            Spacer(modifier = Modifier.height(8.dp))

            // Snake measurement section
            CustomText(
                text = stringResource("measure_snake"),
                fontSize = 16.sp,
                color = AppColors.Snake,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
            )

            SnakeMeasurementSection(viewModel = viewModel)

            // Result display
            if (state.calculatedSnakeLengthCm > 0) {
                Spacer(modifier = Modifier.height(16.dp))
                ResultDisplay(
                    lengthCm = state.calculatedSnakeLengthCm,
                    selectedUnit = state.selectedUnit
                )
            }

            // History display
            Spacer(modifier = Modifier.height(16.dp))
            HistoryDisplay(
                history = state.measurementHistory,
                currentUnit = state.selectedUnit,
                onDeleteRecord = { recordId -> viewModel.deleteHistoryRecord(recordId) }
            )
        }
    }
}

@Composable
private fun ReferenceSection(
    viewModel: MeasurementViewModel,
    pointCount: Int
) {
    val state = viewModel.state
    var lengthText by remember(state.selectedUnit, state.referenceLengthCm) {
        mutableStateOf(state.selectedUnit.fromCentimeters(state.referenceLengthCm).toString())
    }
    var showUnitDropdown by remember { mutableStateOf(false) }

    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
        // Unit selector
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            CustomText(
                text = stringResource("unit"),
                fontSize = 14.sp,
                color = AppColors.TextSecondary
            )
            Box {
                CustomButton(
                    text = "${state.selectedUnit.displayName} (${state.selectedUnit.abbreviation})",
                    onClick = { showUnitDropdown = !showUnitDropdown },
                    backgroundColor = AppColors.GrayLight,
                    modifier = Modifier.fillMaxWidth()
                )
                if (showUnitDropdown) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color.White, RoundedCornerShape(8.dp))
                            .border(2.dp, AppColors.GrayLight, RoundedCornerShape(8.dp))
                            .padding(4.dp)
                    ) {
                        MeasurementUnit.entries.forEach { unit ->
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clip(RoundedCornerShape(4.dp))
                                    .clickable {
                                        viewModel.setUnit(unit)
                                        showUnitDropdown = false
                                    }
                                    .background(
                                        if (unit == state.selectedUnit) AppColors.Accent.copy(alpha = 0.2f)
                                        else Color.Transparent
                                    )
                                    .padding(8.dp)
                            ) {
                                CustomText(
                                    text = "${unit.displayName} (${unit.abbreviation})",
                                    fontSize = 14.sp,
                                    color = AppColors.TextPrimary
                                )
                            }
                        }
                    }
                }
            }
        }

        // Reference length input
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            CustomText(
                text = stringResource("length"),
                fontSize = 14.sp,
                color = AppColors.TextSecondary
            )
            Box(
                modifier = Modifier
                    .width(80.dp)
                    .border(2.dp, AppColors.Reference, RoundedCornerShape(8.dp))
                    .background(Color.White, RoundedCornerShape(8.dp))
                    .padding(8.dp)
            ) {
                BasicTextField(
                    value = lengthText,
                    onValueChange = {
                        lengthText = it
                        it.toFloatOrNull()?.let { value ->
                            viewModel.setReferenceLength(value)
                        }
                    },
                    textStyle = TextStyle(
                        fontSize = 14.sp,
                        color = AppColors.TextPrimary
                    ),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                    singleLine = true
                )
            }
            CustomText(
                text = state.selectedUnit.abbreviation,
                fontSize = 14.sp,
                color = AppColors.TextSecondary
            )
        }

        // Mode button
        CustomButton(
            text = if (state.mode == MeasurementMode.REFERENCE) {
                "✓ Placing Reference Points ($pointCount/2)"
            } else {
                "Place Reference Points ($pointCount/2)"
            },
            onClick = { viewModel.setMode(MeasurementMode.REFERENCE) },
            backgroundColor = if (state.mode == MeasurementMode.REFERENCE) {
                AppColors.Reference
            } else {
                AppColors.GrayLight
            },
            enabled = pointCount < 2,
            modifier = Modifier.fillMaxWidth()
        )

        if (pointCount > 0) {
            CustomText(
                text = stringResource("tap_to_place_point", if (pointCount == 0) stringResource("start") else stringResource("end")),
                fontSize = 12.sp,
                color = AppColors.TextSecondary
            )
        }
    }
}

@Composable
private fun SnakeMeasurementSection(viewModel: MeasurementViewModel) {
    val state = viewModel.state
    val canMeasure = state.referencePoints.size == 2

    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            CustomButton(
                text = if (state.mode == MeasurementMode.SNAKE) {
                    "✓ ${stringResource("placing_points")} (${state.snakePoints.size})"
                } else {
                    "${stringResource("place_points")} (${state.snakePoints.size})"
                },
                onClick = { viewModel.setMode(MeasurementMode.SNAKE) },
                backgroundColor = if (state.mode == MeasurementMode.SNAKE) {
                    AppColors.Snake
                } else {
                    AppColors.GrayLight
                },
                enabled = canMeasure,
                modifier = Modifier.weight(1f)
            )
            CustomButton(
                text = if (state.mode == MeasurementMode.EDIT) "✓ ${stringResource("edit")}" else stringResource("edit"),
                onClick = { viewModel.setMode(MeasurementMode.EDIT) },
                backgroundColor = if (state.mode == MeasurementMode.EDIT) {
                    AppColors.Accent
                } else {
                    AppColors.GrayLight
                },
                enabled = state.snakePoints.isNotEmpty(),
                modifier = Modifier.weight(1f)
            )
        }

        if (state.snakePoints.isNotEmpty()) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                CustomButton(
                    text = stringResource("delete_last"),
                    onClick = { viewModel.deleteLastSnakePoint() },
                    backgroundColor = AppColors.Warning,
                    modifier = Modifier.weight(1f)
                )
                CustomButton(
                    text = stringResource("clear_all_points"),
                    onClick = { viewModel.clearSnakePoints() },
                    backgroundColor = AppColors.Error,
                    modifier = Modifier.weight(1f)
                )
            }
        }

        if (!canMeasure) {
            CustomText(
                text = stringResource("set_reference_first"),
                fontSize = 12.sp,
                color = AppColors.Warning
            )
        } else if (state.snakePoints.isEmpty()) {
            CustomText(
                text = stringResource("tap_along_snake"),
                fontSize = 12.sp,
                color = AppColors.TextSecondary
            )
        }
    }
}

@Composable
private fun ZoomControlsSection(viewModel: MeasurementViewModel) {
    val state = viewModel.state
    val zoomPercentage = (state.zoomLevel * 100).toInt()

    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
        CustomText(
            text = stringResource("zoom_and_pan"),
            fontSize = 14.sp,
            color = AppColors.TextSecondary,
            fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
        )

        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Zoom out button
            CustomButton(
                text = "−",
                onClick = {
                    val newZoom = state.zoomLevel - 0.25f
                    viewModel.setZoom(newZoom)
                },
                backgroundColor = AppColors.GrayLight,
                enabled = state.zoomLevel > state.minZoom,
                modifier = Modifier.weight(1f)
            )

            // Zoom percentage display
            Box(
                modifier = Modifier
                    .weight(2f)
                    .background(AppColors.Accent.copy(alpha = 0.1f), RoundedCornerShape(8.dp))
                    .border(2.dp, AppColors.Accent, RoundedCornerShape(8.dp))
                    .padding(vertical = 8.dp),
                contentAlignment = Alignment.Center
            ) {
                CustomText(
                    text = "$zoomPercentage%",
                    fontSize = 14.sp,
                    color = AppColors.Accent,
                    fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
                )
            }

            // Zoom in button
            CustomButton(
                text = "+",
                onClick = {
                    val newZoom = state.zoomLevel + 0.25f
                    viewModel.setZoom(newZoom)
                },
                backgroundColor = AppColors.GrayLight,
                enabled = state.zoomLevel < state.maxZoom,
                modifier = Modifier.weight(1f)
            )
        }

        // Reset zoom button
        if (state.zoomLevel != 1f || state.panOffset != Offset.Zero) {
            CustomButton(
                text = stringResource("reset_view"),
                onClick = { viewModel.resetZoom() },
                backgroundColor = AppColors.Warning,
                modifier = Modifier.fillMaxWidth()
            )
        }

        CustomText(
            text = stringResource("pinch_to_zoom_hint"),
            fontSize = 11.sp,
            color = AppColors.TextSecondary
        )
    }
}

@Composable
private fun ResultDisplay(lengthCm: Float, selectedUnit: MeasurementUnit) {
    val lengthInUnit = selectedUnit.fromCentimeters(lengthCm)
    val formattedLength = selectedUnit.formatWithUnit(lengthInUnit)

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .background(AppColors.Accent.copy(alpha = 0.1f), RoundedCornerShape(12.dp))
            .border(2.dp, AppColors.Accent, RoundedCornerShape(12.dp))
            .padding(16.dp),
        contentAlignment = Alignment.Center
    ) {
        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            CustomText(
                text = stringResource("snake_length"),
                fontSize = 14.sp,
                color = AppColors.TextSecondary
            )
            CustomText(
                text = formattedLength,
                fontSize = 28.sp,
                color = AppColors.Accent,
                fontWeight = androidx.compose.ui.text.font.FontWeight.Bold
            )
        }
    }
}
