package org.example.project.util

import kotlin.js.Json
import kotlin.js.json

/**
 * Google Analytics implementation for Web (JS)
 */
actual object Analytics {
    private var isInitialized = false
    private var analyticsEnabled = false

    actual fun initialize(analyticsEnabled: Boolean) {
        this.analyticsEnabled = analyticsEnabled
        if (analyticsEnabled && !isInitialized) {
            try {
                // Initialize Google Analytics 4
                // In production, replace GA_MEASUREMENT_ID with your actual measurement ID
                loadGoogleAnalytics("G-XXXXXXXXXX")
                isInitialized = true
                console.log("Google Analytics initialized")
            } catch (e: Exception) {
                console.error("Failed to initialize Google Analytics:", e.message)
            }
        }
    }

    actual fun trackEvent(category: String, action: String, label: String?) {
        if (!analyticsEnabled || !isInitialized) return

        try {
            val eventParams = json(
                "event_category" to category,
                "event_label" to (label ?: "")
            )
            gtag("event", action, eventParams)
        } catch (e: Exception) {
            console.error("Failed to track event:", e.message)
        }
    }

    actual fun trackPageView(path: String) {
        if (!analyticsEnabled || !isInitialized) return

        try {
            val pageParams = json(
                "page_path" to path
            )
            gtag("event", "page_view", pageParams)
        } catch (e: Exception) {
            console.error("Failed to track page view:", e.message)
        }
    }

    actual fun trackMeasurement(lengthCm: Float, unit: String, pointCount: Int) {
        if (!analyticsEnabled || !isInitialized) return

        try {
            val measurementParams = json(
                "event_category" to "Measurement",
                "length_cm" to lengthCm,
                "unit" to unit,
                "point_count" to pointCount
            )
            gtag("event", "snake_measured", measurementParams)
        } catch (e: Exception) {
            console.error("Failed to track measurement:", e.message)
        }
    }

    private fun loadGoogleAnalytics(measurementId: String) {
        js("""
            var script = document.createElement('script');
            script.async = true;
            script.src = 'https://www.googletagmanager.com/gtag/js?id=' + measurementId;
            document.head.appendChild(script);

            window.dataLayer = window.dataLayer || [];
            function gtag(){dataLayer.push(arguments);}
            gtag('js', new Date());
            gtag('config', measurementId);
        """)
    }

    private fun gtag(command: String, eventName: String, params: Json) {
        js("window.gtag")(command, eventName, params)
    }
}
