package org.example.project.util

import androidx.compose.ui.geometry.Offset
import org.example.project.model.MeasurementPoint
import kotlin.math.pow
import kotlin.math.sqrt

object MeasurementCalculator {

    /**
     * Calculate distance between two points using Pythagorean theorem
     */
    fun calculateDistance(point1: Offset, point2: Offset): Float {
        val dx = point2.x - point1.x
        val dy = point2.y - point1.y
        return sqrt(dx.pow(2) + dy.pow(2))
    }

    /**
     * Calculate total length of a polyline through multiple points
     * Uses linear interpolation between consecutive points
     */
    fun calculatePolylineLength(points: List<MeasurementPoint>): Float {
        if (points.size < 2) return 0f

        var totalLength = 0f
        for (i in 0 until points.size - 1) {
            val current = points[i].position
            val next = points[i + 1].position
            totalLength += calculateDistance(current, next)
        }

        return totalLength
    }

    /**
     * Calculate snake length in real-world units (cm)
     * @param snakePoints Points marking the snake's body
     * @param referencePoints Points marking the reference object
     * @param referenceLengthCm Known length of reference object in cm
     * @return Snake length in cm
     */
    fun calculateSnakeLengthInCm(
        snakePoints: List<MeasurementPoint>,
        referencePoints: List<MeasurementPoint>,
        referenceLengthCm: Float
    ): Float {
        if (snakePoints.size < 2 || referencePoints.size < 2) return 0f

        // Calculate pixel lengths
        val snakeLengthPixels = calculatePolylineLength(snakePoints)
        val referenceLengthPixels = calculatePolylineLength(referencePoints)

        if (referenceLengthPixels == 0f) return 0f

        // Calculate scale: pixels per cm
        val pixelsPerCm = referenceLengthPixels / referenceLengthCm

        // Convert snake length from pixels to cm
        return snakeLengthPixels / pixelsPerCm
    }

    /**
     * Calculate distance from a point to a line segment
     * Used for determining if user tapped near a point
     */
    fun distanceToPoint(point: Offset, target: Offset): Float {
        return calculateDistance(point, target)
    }

    /**
     * Find the nearest point to a given position
     * @param position The position to check
     * @param points List of points to search
     * @param maxDistance Maximum distance to consider (in pixels)
     * @return The nearest point if within maxDistance, null otherwise
     */
    fun findNearestPoint(
        position: Offset,
        points: List<MeasurementPoint>,
        maxDistance: Float = 50f
    ): MeasurementPoint? {
        return points
            .map { point -> point to distanceToPoint(position, point.position) }
            .filter { (_, distance) -> distance <= maxDistance }
            .minByOrNull { (_, distance) -> distance }
            ?.first
    }
}
