package org.example.project.resources

import net.sergeych.sprintf.format
import net.sergeych.sprintf.sprintf
import org.example.project.model.Language
import org.example.project.resources.strings.StringsEn
import org.example.project.resources.strings.StringsEs
import org.example.project.resources.strings.StringsFr
import org.example.project.resources.strings.StringsRu


/**
 * Repository for accessing localized strings
 */
object StringsRepository {
    private val translations = mapOf(
        Language.ENGLISH to StringsEn.strings,
        Language.RUSSIAN to StringsRu.strings,
        Language.SPANISH to StringsEs.strings,
        Language.FRENCH to StringsFr.strings
    )

    /**
     * Get a localized string by key for the given language
     * Returns the key itself if translation not found
     */
    fun getString(key: String, language: Language): String {
        return translations[language]?.get(key) ?: key
    }

    /**
     * Get a localized string with format arguments
     */
    fun getString(key: String, language: Language, vararg args: Any): String {
        val toFormatStr = getString(key, language)
        return try {
            toFormatStr.format(*args)
        } catch (e: Exception) {
            toFormatStr
        }
    }
}
