package org.example.project.model

import androidx.compose.ui.geometry.Offset

/**
 * Represents a point on the image for measurement
 * @param id Unique identifier for the point
 * @param position Position in normalized image coordinates (0.0-1.0 range)
 *                 This allows points to remain accurate regardless of zoom/pan/canvas size
 * @param type Type of point (reference or snake)
 */
data class MeasurementPoint(
    val id: String,
    val position: Offset, // Normalized coordinates (0.0-1.0)
    val type: PointType
)

enum class PointType {
    REFERENCE,
    SNAKE
}
